// ── Tweet-count market analysis ──
// Window: Apr 17 16:00 UTC → Apr 24 16:00 UTC (168h total)
// Current: 108 tweets in elapsed hours, ~82.78h remaining

const WINDOW_START_TS = new Date("2026-04-17T16:00:00Z").getTime();
const WINDOW_END_TS   = new Date("2026-04-24T16:00:00Z").getTime();

const nowTs        = ctx.timing.nowTs;
const elapsedHours = (nowTs - WINDOW_START_TS) / 3_600_000;  // ~85.2h
const totalHours   = (WINDOW_END_TS - WINDOW_START_TS) / 3_600_000; // 168h

const observedCount = ctx.news.totalCount; // 108
const ratePerHour   = observedCount / elapsedHours;

// Each market has the same hoursToExpiry; use the first active one
const activeMarkets  = ctx.markets.filter(m => !m.closed && m.hoursToExpiry > 0);
const hoursRemaining = activeMarkets[0]?.hoursToExpiry ?? 0;

const projectedAdditional = ratePerHour * hoursRemaining;
const projectedTotal      = observedCount + projectedAdditional;

// Normal distribution model
// Use inflated std-dev: Poisson baseline sqrt(N) + flat xtracker-discrepancy buffer
const poissonStd  = Math.sqrt(projectedTotal);
const extraBuffer = 20;  // xtracker may count slightly differently from API
const sigma       = Math.sqrt(poissonStd ** 2 + extraBuffer ** 2); // ~30

const mu = projectedTotal;

const { normCDF, binaryProbsFromYesProb, edgeFromProbs } = ctx.helpers;

// P(lo ≤ X ≤ hi) under Normal(mu, sigma)
const pRange = (lo, hi) =>
  normCDF((hi + 1 - mu) / sigma) - normCDF((lo - mu) / sigma);

// Parse range from question text
const parseRange = (question) => {
  const m = question.match(/post (\d+)-(\d+) tweets/);
  if (m) return { lo: +m[1], hi: +m[2] };
  const m2 = question.match(/post (\d+)\+ tweets/);
  if (m2) return { lo: +m2[1], hi: Infinity };
  return null;
};

const THRESHOLD = 0.04;

const results = ctx.markets.map((market) => {
  try {
    if (market.closed || market.hoursToExpiry < 0) {
      return { question: market.question, decision: "hold", reason: "closed" };
    }
    const range = parseRange(market.question);
    if (!range) {
      return { question: market.question, decision: "hold", reason: "could not parse range" };
    }

    const pYes = range.hi === Infinity
      ? 1 - normCDF((range.lo - mu) / sigma)
      : pRange(range.lo, range.hi);

    const mCtx = { market, timing: ctx.timing };
    const probs = binaryProbsFromYesProb(mCtx, Math.min(Math.max(pYes, 1e-6), 1 - 1e-6));
    const edges = edgeFromProbs(probs, mCtx);
    const best  = edges[0].edge >= edges[1].edge ? edges[0] : edges[1];

    return {
      question:    market.question,
      lo:          range.lo,
      hi:          range.hi,
      pYes:        +pYes.toFixed(4),
      marketPrice: market.outcomes.find(o => o.label === "Yes")?.price,
      edge:        +best.edge.toFixed(4),
      side:        best.label,
      fairPrice:   +best.fairPrice.toFixed(4),
      decision:    best.edge >= THRESHOLD ? "buy" : "hold",
    };
  } catch (err) {
    return { question: market.question, decision: "hold", reason: String(err) };
  }
});

return {
  meta: {
    observedCount,
    elapsedHours:       +elapsedHours.toFixed(1),
    ratePerHour:        +ratePerHour.toFixed(3),
    hoursRemaining:     +hoursRemaining.toFixed(1),
    projectedTotal:     +projectedTotal.toFixed(1),
    mu:                 +mu.toFixed(1),
    sigma:              +sigma.toFixed(1),
  },
  markets: results,
};
